import type { Framework } from "@platform/detect";
import type { ResolvedAgent } from "@platform/sdk";

export interface AdaptPlan {
  framework: Framework;
  slug: string;
  name: string;
  description: string;
  /** Repo-relative path to the framework entry module. */
  entryPath: string;
  entryExport?: string;
}

export interface AdaptResult {
  agentRoot: string;
  agent: ResolvedAgent;
  framework: Framework;
  /** True when agent.config.ts was generated by an adapter. */
  generated: boolean;
  plan: AdaptPlan;
}

export interface FrameworkAdapter {
  framework: Framework;
  /** Return a plan when this repo matches framework conventions. */
  plan(repoDir: string): Promise<AdaptPlan | null>;
}
